def generation_panel(ready: bool) -> str:
    disabled = "" if ready else "disabled"
    notice = "" if ready else '<div class="notice">Generation is disabled until ENABLE_LOCAL_MUSICGEN is true, MUSICGEN_MODEL is configured, and the AI worker dependencies are installed.</div>'
    return f'''<section class="card"><h2>Generate music</h2><p class="muted">Runs the configured local MusicGen-compatible model. No placeholder audio is returned.</p><form action="/ui/generate" method="post"><label>Prompt</label><textarea name="prompt" required minlength="8" maxlength="1000" placeholder="Describe genre, instruments, mood and arrangement"></textarea><label>Name</label><input name="name" value="Generated music"><label>Duration in seconds</label><input name="duration_seconds" type="number" value="12" min="4" max="30"><label>Seed</label><input name="seed" type="number" placeholder="Optional"><button type="submit" {disabled}>Generate real audio</button></form>{notice}</section>'''
